-- Insertar las 6 lecciones
INSERT INTO lessons (title, description, order_index) VALUES
('¿Qué es un Requerimiento?', 'Concepto fundamental de requerimiento en ingeniería de software.', 1),
('Funcionales vs No Funcionales', 'Clasificación precisa de requerimientos funcionales y no funcionales.', 2),
('Entrevistas y Cuestionarios', 'Técnicas de elicitación: entrevistas, tipos de preguntas y cuestionarios.', 3),
('User Stories y Criterios de Aceptación', 'Formato, redacción y calidad de historias de usuario.', 4),
('Validación de Requerimientos (SMART)', 'Validación, criterios SMART y detección de defectos.', 5),
('Examen Final: Sistema de Biblioteca Universitaria', 'Caso de estudio: La Universidad Tecnológica del Valle necesita un nuevo sistema de gestión de biblioteca.', 6);

-- =====================================================================
-- Lección 1: ¿Qué es un Requerimiento?
-- =====================================================================
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (1, 'Verdadero/Falso',
     'Responde si las afirmaciones sobre requerimientos son verdaderas o falsas.',
     'TRUE_FALSE', 'BEGINNER', 1, 30,
     '{"questions":[{"text":"Un requerimiento es simplemente una lista de deseos del cliente, sin necesidad de ser verificable.","correctAnswer":false,"feedbackCorrect":"¡Correcto! Un requerimiento debe ser una condición necesaria y verificable, no un deseo vago.","feedbackIncorrect":"Incorrecto. Un requerimiento no es un deseo, sino una capacidad o condición que el sistema debe cumplir de forma objetiva y comprobable."},{"text":"Los errores en los requerimientos pueden provocar sobrecostos y el fracaso del proyecto.","correctAnswer":true,"feedbackCorrect":"Efectivamente. Datos del informe CHAOS y de Wiegers muestran que los defectos en requerimientos son la principal causa de sobrecostos y cancelaciones.","feedbackIncorrect":"En realidad es verdadero. Numerosos estudios demuestran que una mala gestión de requerimientos eleva drásticamente los costos y puede llevar al fracaso del proyecto."},{"text":"Los requerimientos se limitan exclusivamente a las funciones que debe realizar el sistema.","correctAnswer":false,"feedbackCorrect":"¡Bien! Los requerimientos también incluyen restricciones, atributos de calidad (rendimiento, seguridad) y características no funcionales.","feedbackIncorrect":"No es correcto. Además de las funciones, existen requerimientos no funcionales (rendimiento, disponibilidad, etc.) que son igualmente importantes."}]}'::jsonb),

    (1, 'Diálogo con el Sr. García',
     'Simulación de entrevista con un cliente confundido. Elige preguntas para ganar confianza.',
     'MULTIPLE_CHOICE', 'BEGINNER', 2, 50,
     '{"multipleChoiceMode":"DIALOG","initialConfidence":10,"rounds":4,"questions":[{"id":1,"text":"¿Qué problemas específicos está teniendo con la forma en que ahora gestiona a sus clientes?","type":"MUY_BUENA","impact":25,"response":"Buena pregunta… Actualmente lo llevo todo en una libreta y en hojas de Excel sueltas. Se me pierden datos, no sé en qué estado está cada reparación y a veces olvido llamar al cliente cuando su aparato está listo."},{"id":2,"text":"¿Qué tareas concretas le gustaría que el sistema realizara primero?","type":"MUY_BUENA","impact":25,"response":"Principalmente quiero poder registrar cada reparación, saber en qué estado está (diagnóstico, en reparación, lista para entregar) y tener un historial por cliente. Si el sistema me avisa cuando algo está listo, mucho mejor."},{"id":3,"text":"¿Me puede describir cómo es un día típico atendiendo a un cliente, desde que llega hasta que se va?","type":"BUENA","impact":15,"response":"Claro. Cuando un cliente llega, apunto sus datos, describo el problema, le doy un presupuesto aproximado y después realizo la reparación. Luego anoto cuándo se entregó y cuánto cobré. Todo en papel, como le digo."},{"id":4,"text":"¿Aproximadamente cuántos clientes atiende al mes? ¿Y cuántos aparatos repara?","type":"BUENA","impact":15,"response":"Atiendo unos 50 o 60 clientes al mes. La mayoría trae electrodomésticos pequeños; algunos repiten. Así que calculo entre 70 y 80 reparaciones mensuales."},{"id":5,"text":"¿Tiene algún presupuesto aproximado para este sistema?","type":"NEUTRA","impact":0,"response":"No lo he pensado seriamente. Algo razonable, pero primero quiero entender qué puede hacer el sistema por mí."},{"id":6,"text":"¿Prefiere que el sistema tenga una apariencia moderna con colores vivos?","type":"NEUTRA","impact":0,"response":"Supongo que sería bonito, pero no me preocupa mucho. Lo importante es que sea fácil de usar y no me complique más el trabajo."},{"id":7,"text":"¿Le gustaría que el sistema también enviara automáticamente ofertas por correo electrónico?","type":"MALA","impact":-10,"response":"Ofertas… No lo había pensado. A lo mejor más adelante, pero ahora mi prioridad es organizar las reparaciones que ya tengo."},{"id":8,"text":"¿Quiere que la aplicación sea de escritorio o mejor una página web?","type":"MALA","impact":-10,"response":"No estoy seguro. Mientras pueda usarlo sin problemas… ¿Qué me recomienda? Aunque antes deberíamos ver qué funciones necesito, ¿no?"}],"scoring":{"80":50,"60":35,"40":20,"0":0}}'::jsonb),

    (1, 'Pares seleccionables',
     'Empareja los conceptos con sus definiciones correctas.',
     'MATCH_PAIRS', 'BEGINNER', 3, 20,
     '{"pairs":[{"concept":"Requerimiento","definition":"Condición o capacidad que debe cumplir un sistema para satisfacer una necesidad de un stakeholder."},{"concept":"Stakeholder","definition":"Persona u organización que tiene un interés o se ve afectada por el sistema."},{"concept":"Elicitación","definition":"Proceso de obtener información de los stakeholders para descubrir los requerimientos reales."},{"concept":"Especificación de requerimientos","definition":"Documento formal que describe de manera detallada y estructurada lo que el sistema debe hacer."}]}'::jsonb);

-- =====================================================================
-- Lección 2: Funcionales vs No Funcionales
-- =====================================================================
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (2, 'Opción múltiple',
     'Responde preguntas sobre requerimientos funcionales y no funcionales.',
     'MULTIPLE_CHOICE', 'BEGINNER', 1, 30,
     '{"multipleChoiceMode":"QUIZ","questions":[{"question":"El sistema debe enviar un correo electrónico al cliente cuando su pedido cambie de estado. ¿Qué tipo de requerimiento es?","options":[{"text":"A) No funcional, porque habla de un envío de correo.","correct":false},{"text":"B) Funcional, porque describe una acción concreta que el sistema debe realizar.","correct":true},{"text":"C) No funcional, porque involucra comunicación externa.","correct":false},{"text":"D) Funcional, pero solo si se especifica el formato del correo.","correct":false}],"feedbackCorrect":"¡Correcto! Es una función específica: el sistema debe ejecutar la acción de enviar un correo ante un evento determinado.","feedbackIncorrect":"La opción correcta es la B. Este requerimiento define una conducta observable (enviar un correo), por tanto es funcional."},{"question":"El sistema debe soportar hasta 500 usuarios concurrentes sin degradar el tiempo de respuesta. ¿Qué tipo de requerimiento es?","options":[{"text":"A) Funcional, porque especifica una capacidad del sistema.","correct":false},{"text":"B) No funcional, porque describe una condición de rendimiento.","correct":true},{"text":"C) Funcional, porque menciona usuarios.","correct":false},{"text":"D) No funcional, pero solo si se especifica el hardware.","correct":false}],"feedbackCorrect":"¡Bien! Está relacionado con la capacidad y el rendimiento, atributos típicamente no funcionales.","feedbackIncorrect":"La opción correcta es B. Aunque hable de \"usuarios\", no describe una función sino un requisito de rendimiento (throughput y concurrencia)."},{"question":"¿Cuál de las siguientes afirmaciones es verdadera?","options":[{"text":"A) Todos los requerimientos no funcionales son restricciones de hardware.","correct":false},{"text":"B) Un requerimiento funcional nunca incluye referencias a la interfaz de usuario.","correct":false},{"text":"C) La seguridad y la usabilidad son ejemplos de requerimientos no funcionales.","correct":true},{"text":"D) Los requerimientos no funcionales son menos importantes que los funcionales.","correct":false}],"feedbackCorrect":"Correcto. Seguridad, usabilidad, rendimiento y disponibilidad son categorías clásicas de requerimientos no funcionales.","feedbackIncorrect":"La opción correcta es C. Los atributos de calidad como seguridad y usabilidad son, por definición, requerimientos no funcionales."}]}'::jsonb),

    (2, 'Diagrama de Venn',
     'Arrastra cada ítem a la zona correcta: Funcional, No funcional o Ambos.',
     'DRAG_DROP', 'BEGINNER', 2, 40,
     '{"dragMode":"VENN","zones":{"left":"Funcional","right":"No funcional","intersection":"Ambos / En la frontera"},"items":[{"id":1,"text":"El sistema debe permitir al usuario exportar el historial a Excel.","correctZone":"FUNCIONAL","explanation":"Correcto (Funcional). Es una acción concreta: exportar datos."},{"id":2,"text":"La aplicación web debe cargar completamente en menos de 3 segundos con una conexión de 5 Mbps.","correctZone":"NO_FUNCIONAL","explanation":"Correcto (No funcional). Es un requisito de rendimiento claramente medible."},{"id":3,"text":"El sistema debe validar que el correo ingresado tenga un formato correcto antes de registrar al usuario.","correctZone":"FUNCIONAL","explanation":"Correcto (Funcional). Describe una regla de negocio y un paso en el proceso de registro."},{"id":4,"text":"Los datos personales de los clientes deben estar cifrados tanto en tránsito como en reposo.","correctZone":"NO_FUNCIONAL","explanation":"Correcto (No funcional). Es un atributo de seguridad."},{"id":5,"text":"El sistema debe ser fácil de usar para personas mayores de 60 años sin formación técnica.","correctZone":"NO_FUNCIONAL","explanation":"Correcto (No funcional). Es un requerimiento de usabilidad."},{"id":6,"text":"El administrador debe poder modificar el porcentaje de IVA desde un panel de configuración.","correctZone":"BOTH","explanation":"Correcto (Ambos / Frontera). La acción es funcional, pero la intención es facilitar la mantenibilidad (no funcional)."},{"id":7,"text":"El sistema debe funcionar correctamente en los navegadores Chrome, Firefox y Safari.","correctZone":"NO_FUNCIONAL","explanation":"Correcto (No funcional). Describe portabilidad/compatibilidad."},{"id":8,"text":"El sistema debe enviar una notificación push al móvil del usuario cuando su pago sea rechazado.","correctZone":"FUNCIONAL","explanation":"Correcto (Funcional). Especifica un comportamiento concreto."}]}'::jsonb),

    (2, 'Tarjetas deslizables',
     'Desliza cada tarjeta para clasificar como Funcional (derecha) o No funcional (izquierda).',
     'SWIPE_CARDS', 'BEGINNER', 3, 30,
     '{"cards":[{"text":"El sistema debe generar un informe mensual de ventas.","correctSwipe":"RIGHT","feedback":"Acierto: Correcto. Generar un informe es una función del sistema. | Fallo: ¡Ups! Generar un informe es una acción, por tanto es un requerimiento funcional."},{"text":"La disponibilidad del sistema debe ser del 99.5 % durante el horario comercial.","correctSwipe":"LEFT","feedback":"Acierto: Muy bien. La disponibilidad es un atributo de calidad (no funcional). | Fallo: Incorrecto. La disponibilidad es un requisito no funcional clásico."},{"text":"El usuario debe poder filtrar los productos por rango de precios.","correctSwipe":"RIGHT","feedback":"Acierto: Bien. Filtrar es una operación que el sistema realiza, un requerimiento funcional. | Fallo: No. Filtrar productos es una funcionalidad concreta, no un atributo de calidad."},{"text":"La aplicación debe soportar hasta 10 000 productos en el catálogo sin pérdida de rendimiento.","correctSwipe":"LEFT","feedback":"Acierto: Correcto. Habla de capacidad y rendimiento, no funcional. | Fallo: Error. Se trata de una restricción de capacidad (rendimiento), no de una función específica."},{"text":"El sistema debe permitir la recuperación de contraseña mediante enlace enviado al correo registrado.","correctSwipe":"RIGHT","feedback":"Acierto: Genial. La recuperación de contraseña es una función clara. | Fallo: Incorrecto. Recuperar contraseña es una acción que el sistema ejecuta; es funcional."},{"text":"El tiempo de aprendizaje para que un cajero nuevo opere el sistema no debe superar 2 horas.","correctSwipe":"LEFT","feedback":"Acierto: Muy bien. Es un requerimiento de usabilidad (no funcional). | Fallo: Te equivocaste. La facilidad de aprendizaje es un atributo de calidad, por tanto no funcional."},{"text":"Cuando un cliente cancele una reserva, el sistema debe liberar automáticamente el cupo en menos de 1 minuto.","correctSwipe":"RIGHT","feedback":"Acierto: Correcto. La acción de liberar el cupo es funcional; el plazo añade una restricción de rendimiento. | Fallo: La tarjeta tiene dos partes, pero el núcleo es una función (liberar), por eso se considera funcional con restricción adicional."},{"text":"La base de datos debe poder recuperarse completamente en menos de 4 horas tras un fallo catastrófico.","correctSwipe":"LEFT","feedback":"Acierto: Exacto. Es un requisito de fiabilidad/recuperación, no funcional. | Fallo: No acertaste. Recuperación de base de datos es una capacidad técnica, pero se expresa como restricción temporal; es no funcional."},{"text":"El sistema debe registrar en un log cada acceso fallido, incluyendo IP y fecha.","correctSwipe":"RIGHT","feedback":"Acierto: Bien. Registrar eventos de auditoría es una función. | Fallo: Error. Llevar un log de accesos fallidos es una acción concreta, un requerimiento funcional."},{"text":"El sistema debe cumplir con el estándar WCAG 2.1 nivel AA en todas sus páginas.","correctSwipe":"LEFT","feedback":"Acierto: Correcto. Cumplir un estándar de accesibilidad es un atributo de calidad (no funcional). | Fallo: Incorrecto. Es un requisito de calidad externo, por tanto no funcional."}]}'::jsonb);

-- =====================================================================
-- Lección 3: Entrevistas y Cuestionarios
-- =====================================================================
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (3, 'Clasifica el tipo de pregunta',
     'Arrastra cada pregunta a la categoría: Abierta, Cerrada, Sesgada, De sondeo.',
     'DRAG_DROP', 'BEGINNER', 1, 30,
     '{"dragMode":"CATEGORY_COLUMNS","categories":["Abierta","Cerrada","Sesgada","De sondeo"],"items":[{"text":"¿Podría describirme paso a paso cómo realiza actualmente el cierre de caja?","category":"Abierta","feedback":"Invita a una explicación detallada sin límites; es una pregunta abierta."},{"text":"¿Cuántos clientes atienden en un día promedio?","category":"Cerrada","feedback":"Se espera un número concreto; es una pregunta cerrada."},{"text":"¿No cree que sería mejor unificar todas las pantallas en una sola interfaz?","category":"Sesgada","feedback":"Está induciendo la respuesta hacia una solución concreta, es sesgada y debe evitarse."},{"text":"Usted mencionó que a veces se pierden pedidos. ¿Recuerda la última vez que ocurrió? Cuénteme qué pasó.","category":"De sondeo","feedback":"Retoma un punto anterior para profundizar; es una pregunta de sondeo."},{"text":"¿Utilizan algún programa informático para gestionar el inventario?","category":"Cerrada","feedback":"Se puede responder con un sí o un no; es cerrada."},{"text":"¿Qué es lo que más le frustra del sistema actual?","category":"Abierta","feedback":"Permite una respuesta emocional y amplia, es abierta."}]}'::jsonb),

    (3, 'Ordena la preparación',
     'Ordena correctamente los pasos para preparar una entrevista de elicitación.',
     'DRAG_DROP', 'BEGINNER', 2, 30,
     '{"dragMode":"SORT_ORDER","steps":[{"order":1,"text":"Definir el objetivo de la entrevista: ¿qué información necesito obtener exactamente?"},{"order":2,"text":"Identificar al stakeholder adecuado: la persona que tiene el conocimiento y la autoridad sobre el tema."},{"order":3,"text":"Elaborar la guía de preguntas: preparar preguntas abiertas, cerradas y de sondeo, evitando sesgos."},{"order":4,"text":"Concertar la cita y explicar el propósito: el entrevistado debe saber la duración y el motivo."},{"order":5,"text":"Documentar los resultados inmediatamente después: pasar las notas en limpio y, si es posible, validarlas con el entrevistado."}]}'::jsonb),

    (3, 'Entrevista con la Sra. Gómez',
     'Simulación de entrevista con la directora de banca minorista. Elige las mejores preguntas.',
     'MULTIPLE_CHOICE', 'BEGINNER', 3, 40,
     '{"multipleChoiceMode":"DIALOG","context":"Gracias por venir. Como le comenté, queremos modernizar nuestra banca en línea. Actualmente los clientes solo pueden consultar saldos y hacer transferencias básicas, y el sistema se cae con frecuencia en quincenas. ¿Por dónde empezamos?","rounds":[{"roundContext":"Sra. Gómez: Gracias por venir. Como le comenté, queremos modernizar nuestra banca en línea...","options":[{"text":"¿Qué nuevas funcionalidades le gustaría que tuviera el portal?","score":5,"response":"Buena pregunta. Nuestros clientes se quejan de que el portal es muy lento..."},{"text":"¿No le parece que lo más urgente es una app móvil con reconocimiento facial?","score":0,"response":"No lo había pensado así. ¿Cree que eso resolvería los problemas?"},{"text":"Cuénteme, ¿cómo describiría la experiencia actual de sus clientes con la banca en línea? ¿Qué problemas son los más frecuentes?","score":10,"response":"Buena pregunta. Nuestros clientes se quejan de que el portal es muy lento y a veces no pueden hacer operaciones en horario de alta demanda. Además, el proceso para solicitar un préstamo o una tarjeta de crédito es completamente presencial; les gustaría poder iniciarlo en línea."}]},{"roundContext":"Sra. Gómez: Sí, la verdad es que el portal actual no soporta bien los picos de uso. Aparte, los clientes jóvenes piden poder hacer todo desde el celular, y nuestros clientes mayores se quejan de que la letra es muy pequeña.","options":[{"text":"¿Ha pensado en desarrollar una aplicación móvil separada o prefiere un portal web adaptativo?","score":5,"response":"No lo he decidido aún. Me gustaría escuchar recomendaciones."},{"text":"Respecto a los picos de uso, ¿podría darme datos concretos? Por ejemplo, ¿cuántos usuarios simultáneos intentan acceder en una quincena y cuántas operaciones se procesan?","score":10,"response":"En quincena tenemos hasta 300 usuarios simultáneos y unas 2000 transacciones por hora. Nuestro servidor actual no da abasto."},{"text":"Los clientes mayores necesitan una interfaz más simple. ¿Qué le parecería un modo de alto contraste y un asistente virtual por voz?","score":0,"response":"No había pensado en esas funcionalidades concretas. ¿Son realmente necesarias?"}]},{"roundContext":"Sra. Gómez: En quincena tenemos hasta 300 usuarios simultáneos y unas 2000 transacciones por hora. Nuestro servidor actual no da abasto.","options":[{"text":"¿Qué tipo de transacciones realizan con mayor frecuencia? ¿Hay algunas que sean más críticas que otras?","score":10,"response":"Principalmente transferencias y pagos de servicios. También consultas de saldo. Lo más crítico es que las transferencias no fallen, porque luego nos reclaman."},{"text":"¿Quiere que el nuevo sistema soporte 5000 transacciones por hora?","score":5,"response":"No sé si es necesario tanto, pero suena bien."},{"text":"Eso suena a un problema de hardware. ¿Han pensado en migrar a un proveedor de nube como AWS?","score":0,"response":"No hemos evaluado la nube. ¿Es imprescindible?"}]},{"roundContext":"Sra. Gómez: Principalmente transferencias y pagos de servicios. También consultas de saldo. Lo más crítico es que las transferencias no fallen, porque luego nos reclaman.","options":[{"text":"Para ir cerrando, ¿hay algo más que no hayamos hablado y que considere importante para el proyecto?","score":10,"response":"Pues ahora que lo menciona, nos gustaría que el sistema permita a los clientes agendar citas en sucursal."},{"text":"Perfecto. Entonces el sistema debe garantizar transferencias 100 % exitosas. ¿Qué otro requisito debo incluir?","score":5,"response":"Bueno, también la agilidad en las consultas."},{"text":"Creo que ya tengo suficiente. Le enviaré un prototipo la próxima semana. ¿Le parece?","score":0,"response":"¿Un prototipo tan pronto? Preferiría que antes documentemos bien lo que necesitamos."}]}],"scoring":{"maxScore":40}}'::jsonb);

-- =====================================================================
-- Lección 4: User Stories y Criterios de Aceptación
-- =====================================================================
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (4, 'Verdadero/Falso',
     'Afirmaciones sobre user stories.',
     'TRUE_FALSE', 'BEGINNER', 1, 30,
     '{"questions":[{"text":"Una user story debe incluir obligatoriamente un rol, una función deseada y un beneficio esperado para considerarse bien formulada.","correctAnswer":true,"feedbackCorrect":"Correcto. El formato completo (Como… quiero… para…) asegura que se conozca quién lo necesita, qué necesita y por qué.","feedbackIncorrect":"La respuesta correcta es Verdadero. El modelo estándar incluye los tres elementos; omitir el beneficio resta claridad sobre el valor de negocio."},{"text":"Las user stories son propiedad exclusiva del Product Owner y no deben ser discutidas con el equipo de desarrollo.","correctAnswer":false,"feedbackCorrect":"¡Muy bien! Aunque el Product Owner suele definirlas, su refinamiento y detalle se enriquece con la participación de todo el equipo.","feedbackIncorrect":"Incorrecto. Las user stories son una herramienta colaborativa: el equipo participa en su comprensión, estimación y definición de criterios de aceptación."},{"text":"El acrónimo INVEST se utiliza para verificar que una user story tenga una interfaz visual atractiva.","correctAnswer":false,"feedbackCorrect":"Correcto. INVEST evalúa características de calidad de la historia (Independiente, Negociable, Valiosa, Estimable, Pequeña, Testable).","feedbackIncorrect":"No. INVEST es una guía para juzgar si una historia está bien formulada desde el punto de vista de la planificación, no del aspecto gráfico."}]}'::jsonb),

    (4, 'Constructor de user stories',
     'Completa las user stories arrastrando roles, acciones y beneficios.',
     'DRAG_DROP', 'BEGINNER', 2, 40,
     '{"dragMode":"FILL_BLANKS","stories":[{"role":"Alumno","action":"filtrar cursos por nivel de dificultad","benefit":"encontrar cursos adecuados a mi nivel"},{"role":"Instructor","action":"subir un nuevo curso con videos y apuntes","benefit":"compartir mis conocimientos con los estudiantes"},{"role":"Administrador","action":"generar un reporte mensual de inscripciones","benefit":"monitorear el desempeño del negocio"},{"role":"Alumno","action":"marcar una lección como completada","benefit":"llevar un registro de mi progreso"}],"tokens":[{"text":"Alumno","type":"ROLE"},{"text":"Instructor","type":"ROLE"},{"text":"Administrador","type":"ROLE"},{"text":"filtrar cursos por nivel de dificultad","type":"ACTION"},{"text":"subir un nuevo curso con videos y apuntes","type":"ACTION"},{"text":"generar un reporte mensual de inscripciones","type":"ACTION"},{"text":"marcar una lección como completada","type":"ACTION"},{"text":"encontrar cursos adecuados a mi nivel","type":"BENEFIT"},{"text":"compartir mis conocimientos con los estudiantes","type":"BENEFIT"},{"text":"monitorear el desempeño del negocio","type":"BENEFIT"},{"text":"llevar un registro de mi progreso","type":"BENEFIT"}]}'::jsonb),

    (4, 'Tarjetas deslizables',
     'Desliza para clasificar user stories bien o mal formuladas.',
     'SWIPE_CARDS', 'BEGINNER', 3, 30,
     '{"cards":[{"text":"Como usuario, quiero iniciar sesión.","correctSwipe":"LEFT","feedback":"Mal. Falta el beneficio (''para…''). La historia es incompleta."},{"text":"Como cliente, quiero filtrar productos por precio para encontrar ofertas.","correctSwipe":"RIGHT","feedback":"Bien. Está completa: rol, función y beneficio claros."},{"text":"Como administrador, quiero un botón azul en la página de inicio.","correctSwipe":"LEFT","feedback":"Mal. Describe una decisión de diseño en lugar de una funcionalidad."},{"text":"Como vendedor, quiero registrar una nueva venta para llevar el control de ingresos.","correctSwipe":"RIGHT","feedback":"Bien. Formato correcto y expresa una necesidad real."},{"text":"Como sistema, quiero enviar una notificación por correo.","correctSwipe":"LEFT","feedback":"Mal. El rol ''sistema'' no es un usuario real."},{"text":"Como usuario, quiero que la aplicación sea rápida.","correctSwipe":"LEFT","feedback":"Mal. Es un requisito no funcional, no una historia de usuario concreta."},{"text":"Quiero poder ver mis pedidos anteriores.","correctSwipe":"LEFT","feedback":"Mal. Falta el rol, no se sabe desde qué perspectiva se pide."},{"text":"Como cliente, quiero cancelar un pedido que aún no ha sido enviado para evitar gastos innecesarios.","correctSwipe":"RIGHT","feedback":"Bien. Clara, completa y con beneficio explícito."},{"text":"Como administrador, quiero que el sistema utilice una base de datos SQL Server.","correctSwipe":"LEFT","feedback":"Mal. Especifica una solución técnica, no una necesidad del usuario."},{"text":"Como alumno, quiero descargar el certificado del curso en PDF para adjuntarlo a mi currículum.","correctSwipe":"RIGHT","feedback":"Bien. Bien estructurada: rol, función concreta y propósito evidente."}]}'::jsonb);

-- =====================================================================
-- Lección 5: Validación de Requerimientos (SMART)
-- =====================================================================
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (5, 'Opción múltiple',
     'Preguntas sobre validación SMART.',
     'MULTIPLE_CHOICE', 'BEGINNER', 1, 30,
     '{"multipleChoiceMode":"QUIZ","questions":[{"question":"¿Cuál de las siguientes características NO forma parte del acrónimo SMART para evaluar requerimientos?","options":[{"text":"A) Specific (específico)","correct":false},{"text":"B) Measurable (medible)","correct":false},{"text":"C) Elegant (elegante)","correct":true},{"text":"D) Testable (verificable)","correct":false}],"feedbackCorrect":"Correcto. SMART significa Specific, Measurable, Achievable, Relevant, Testable. La estética no es un criterio de validación.","feedbackIncorrect":"La opción correcta es C. \"Elegant\" no forma parte de SMART; los criterios reales son Specific, Measurable, Achievable, Relevant y Testable."},{"question":"Un requerimiento que indica: \"El sistema debe procesar los pagos rápido\" presenta principalmente un defecto de:","options":[{"text":"A) Incompletitud","correct":false},{"text":"B) Ambigüedad","correct":true},{"text":"C) Inviabilidad","correct":false},{"text":"D) Contradicción","correct":false}],"feedbackCorrect":"¡Correcto! El término \"rápido\" es vago y se puede interpretar de muchas maneras; es un ejemplo clásico de ambigüedad.","feedbackIncorrect":"La respuesta correcta es B. \"Rápido\" es un calificativo subjetivo que hace que el requerimiento sea ambiguo."},{"question":"¿Cuál de las siguientes opciones es una técnica de validación de requerimientos reconocida?","options":[{"text":"A) Refactorización del código","correct":false},{"text":"B) Revisión por pares (walkthrough)","correct":true},{"text":"C) Pruebas de carga","correct":false},{"text":"D) Integración continua","correct":false}],"feedbackCorrect":"Exacto. Las revisiones de la especificación con colegas son una de las técnicas más efectivas para detectar defectos en los requerimientos.","feedbackIncorrect":"La opción correcta es B. Las revisiones (walkthroughs e inspecciones) se aplican directamente sobre los documentos de requisitos para validarlos."}]}'::jsonb),

    (5, 'Reescribe el requisito',
     'Corrige los requerimientos defectuosos para hacerlos SMART.',
     'TEXT_INPUT', 'BEGINNER', 2, 40,
     '{"textInputMode":"REWRITE","items":[{"originalText":"El sistema debe ser rápido.","highlightWords":["rápido"],"hints":{"rápido":"¿Qué tan rápido? Define un tiempo máximo de respuesta en segundos."},"modelAnswer":"El sistema debe responder a cualquier petición en menos de 2 segundos para el 95 % de las solicitudes.","evaluation":{"type":"contains","requiredPatterns":["\\d+\\s*segundos?"]}},{"originalText":"El sistema debe soportar muchos usuarios.","highlightWords":["muchos"],"hints":{"muchos":"Especifica una cantidad concreta: usuarios concurrentes, totales, etc."},"modelAnswer":"El sistema debe soportar hasta 500 usuarios concurrentes.","evaluation":{"type":"contains","requiredPatterns":["\\d+","usuarios"]}},{"originalText":"La interfaz debe ser fácil de usar.","highlightWords":["fácil"],"hints":{"fácil":"¿Cómo medirías la facilidad? Piensa en tiempo de aprendizaje o tasa de errores."},"modelAnswer":"Un usuario nuevo debe poder completar una compra en menos de 5 minutos.","evaluation":{"type":"contains","requiredPatterns":["\\d+","minutos?"]}},{"originalText":"El sistema debe generar informes adecuados.","highlightWords":["adecuados"],"hints":{"adecuados":"Define contenido, formato y frecuencia del informe."},"modelAnswer":"El sistema debe generar un informe semanal en PDF con las ventas desglosadas por producto.","evaluation":{"type":"contains","requiredPatterns":["PDF","semanal"]}},{"originalText":"El sistema debe ser seguro.","highlightWords":["seguro"],"hints":{"seguro":"¿Qué medidas de seguridad concretas implementará?"},"modelAnswer":"El sistema debe cifrar los datos personales con AES-256 y exigir autenticación de dos factores para los administradores.","evaluation":{"type":"contains","requiredPatterns":["cifrar","AES"]}}]}'::jsonb),

    (5, 'Clasifica el defecto',
     'Arrastra cada requerimiento defectuoso al tipo de defecto que presenta.',
     'DRAG_DROP', 'BEGINNER', 3, 30,
     '{"dragMode":"CATEGORY_COLUMNS","categories":["Ambigüedad","Incompletitud","Contradicción"],"items":[{"text":"El sistema debe responder rápidamente.","category":"Ambigüedad","feedback":"\"Rápidamente\" es vago y subjetivo. No se puede medir."},{"text":"El sistema debe generar un reporte de ventas.","category":"Incompletitud","feedback":"Falta información clave: contenido, formato, periodicidad."},{"text":"El sistema debe estar disponible 24/7 y además realizar copias de seguridad cada medianoche.","category":"Contradicción","feedback":"Las copias de seguridad suelen exigir una pausa del servicio, lo que contradice la disponibilidad continua."},{"text":"El sistema debe ser compatible con todos los navegadores populares.","category":"Ambigüedad","feedback":"\"Populares\" es un término impreciso; además falta una lista explícita."},{"text":"El sistema debe permitir el acceso a cualquier persona en internet y a la vez restringir el acceso solo a personal autorizado.","category":"Contradicción","feedback":"Un enunciado permite acceso abierto y el otro solo a autorizados; ambos no pueden ser ciertos a la vez."},{"text":"El sistema debe calcular el impuesto.","category":"Incompletitud","feedback":"No se indica qué impuesto, con qué tasa, ni en qué momento se aplica."}]}'::jsonb);

-- =====================================================================
-- Lección 6: Examen Final – Sistema de Biblioteca Universitaria
-- =====================================================================
-- Pregunta 1 – Opción múltiple (Funcional vs No funcional)
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 1 – Tipo de requerimiento',
     'Identifica si el requerimiento es funcional o no funcional.',
     'MULTIPLE_CHOICE', 'INTERMEDIATE', 1, 10,
     '{"examMode":true,"multipleChoiceMode":"QUIZ","caseContext":"La Universidad Tecnológica del Valle necesita un nuevo sistema de gestión de biblioteca. Actualmente usan un proceso manual con fichas de papel. Los estudiantes pueden pedir prestados hasta 3 libros por 15 días. Los profesores pueden pedir hasta 10 libros por 30 días. El sistema debe registrar préstamos, devoluciones, multas por retraso ($1,000 por día), y permitir reservar libros que estén prestados. La biblioteca tiene 5,000 estudiantes, 500 profesores y 20,000 libros. En horas pico (12 pm - 2 pm), hay hasta 200 solicitudes simultáneas. El personal de biblioteca (5 personas) necesita un panel para gestionar préstamos y generar reportes semanales de libros más prestados. La universidad planea integrar este sistema con el sistema de pagos en línea para cobrar multas automáticamente.","questions":[{"question":"\"El sistema debe permitir que un estudiante renueve un préstamo siempre que no haya otro usuario que haya reservado el mismo libro.\" Selecciona el tipo de requerimiento:","options":[{"text":"A) No funcional, porque habla de una restricción.","correct":false},{"text":"B) Funcional, porque describe una acción concreta que realiza el sistema.","correct":true},{"text":"C) No funcional, porque menciona \"reserva\".","correct":false},{"text":"D) Funcional, pero solo si se implementa con un botón visible.","correct":false}],"feedbackCorrect":"Correcto. Renovar un préstamo bajo ciertas condiciones es una función del sistema; la restricción forma parte de la regla de negocio, no la convierte en un requerimiento no funcional.","feedbackIncorrect":"La respuesta correcta es B. El enunciado describe una conducta que el sistema debe exhibir (renovar préstamo) con una condición; eso es un requerimiento funcional."}]}'::jsonb);

-- Pregunta 2 – Opción múltiple (No funcional)
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 2 – Tipo de requerimiento',
     'Identifica si el requerimiento es funcional o no funcional.',
     'MULTIPLE_CHOICE', 'INTERMEDIATE', 2, 10,
     '{"examMode":true,"multipleChoiceMode":"QUIZ","questions":[{"question":"\"El sistema debe ser capaz de manejar hasta 200 solicitudes simultáneas en las horas pico sin que el tiempo de respuesta supere los 3 segundos.\" Selecciona el tipo de requerimiento:","options":[{"text":"A) Funcional, porque especifica un límite de tiempo.","correct":false},{"text":"B) Funcional, porque menciona \"solicitudes\".","correct":false},{"text":"C) No funcional, porque define una restricción de rendimiento.","correct":true},{"text":"D) No funcional, pero solo si se mide con una herramienta.","correct":false}],"feedbackCorrect":"Excelente. La capacidad de carga y el tiempo de respuesta son atributos de calidad, por tanto no funcionales.","feedbackIncorrect":"La opción correcta es C. Aunque mencione \"solicitudes\", lo central es la restricción de concurrencia y rendimiento."}]}'::jsonb);

-- Pregunta 3 – Verdadero/Falso
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 3 – Verdadero/Falso',
     'Determina si la afirmación sobre el requerimiento es verdadera o falsa.',
     'TRUE_FALSE', 'INTERMEDIATE', 3, 10,
     '{"examMode":true,"questions":[{"text":"\"La integración con el sistema de pagos en línea es un requerimiento no funcional, porque describe una interfaz externa.\"","correctAnswer":false,"feedbackCorrect":"Muy bien. Es un requerimiento funcional: el sistema debe realizar la acción de comunicarse con el sistema de pagos; la integración es una función.","feedbackIncorrect":"Es falso. La integración con otro sistema es una capacidad que el sistema debe tener, por lo tanto es un requerimiento funcional."}]}'::jsonb);

-- Pregunta 4 – Verdadero/Falso
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 4 – Verdadero/Falso',
     'Determina si la afirmación sobre el requerimiento es verdadera o falsa.',
     'TRUE_FALSE', 'INTERMEDIATE', 4, 10,
     '{"examMode":true,"questions":[{"text":"\"Que las multas sean de $1,000 por día es un requerimiento funcional, porque define un valor monetario concreto.\"","correctAnswer":true,"feedbackCorrect":"Correcto. El cálculo de la multa y su valor es una regla de negocio que el sistema debe implementar; es un requerimiento funcional.","feedbackIncorrect":"Es verdadero. La regla de negocio \"calcular multa = días de retraso × $1,000\" es una función del sistema."}]}'::jsonb);

-- Pregunta 5 – Tarjetas deslizables: User stories bien o mal formuladas
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 5 – User Stories',
     'Desliza cada tarjeta para clasificar si la user story está bien o mal formulada.',
     'SWIPE_CARDS', 'INTERMEDIATE', 5, 10,
     '{"examMode":true,"cards":[{"text":"Como estudiante, quiero reservar un libro para asegurarme de que esté disponible cuando lo necesite.","correctSwipe":"RIGHT","feedback":"Bien. Formato completo y beneficio claro."},{"text":"Como usuario, quiero que el sistema utilice una base de datos en PostgreSQL.","correctSwipe":"LEFT","feedback":"Mal. Detalle técnico innecesario; la historia debe centrarse en el qué, no en el cómo."},{"text":"Quiero poder ver los libros que tengo prestados.","correctSwipe":"LEFT","feedback":"Mal. Falta el rol; no se identifica quién necesita la funcionalidad."},{"text":"Como bibliotecario, quiero generar un reporte semanal de los libros más prestados para identificar tendencias de lectura.","correctSwipe":"RIGHT","feedback":"Bien. Clara, completa y con propósito."},{"text":"Como profesor, quiero que el sistema sea rápido.","correctSwipe":"LEFT","feedback":"Mal. Es vago y no describe una funcionalidad concreta; es un requerimiento no funcional mal expresado como user story."}]}'::jsonb);

-- Pregunta 6 – Diagrama de Venn: Clasifica en Funcional / No funcional / Ambos
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 6 – Diagrama de Venn',
     'Arrastra cada ítem a la zona correcta: Funcional, No funcional o Ambos.',
     'DRAG_DROP', 'INTERMEDIATE', 6, 10,
     '{"examMode":true,"dragMode":"VENN","zones":{"left":"Funcional","right":"No funcional","intersection":"Ambos / En la frontera"},"items":[{"id":1,"text":"El personal debe poder registrar la devolución de un libro escaneando el código de barras.","correctZone":"FUNCIONAL","explanation":"Es una acción concreta (registrar devolución)."},{"id":2,"text":"El sistema debe estar disponible el 99.5 % del horario de atención.","correctZone":"NO_FUNCIONAL","explanation":"Disponibilidad, atributo de calidad."},{"id":3,"text":"El sistema debe ser fácil de usar por los bibliotecarios, que tienen conocimientos informáticos básicos.","correctZone":"NO_FUNCIONAL","explanation":"Usabilidad, atributo de calidad."},{"id":4,"text":"El sistema debe permitir modificar el monto de la multa diaria sin necesidad de desplegar una nueva versión.","correctZone":"BOTH","explanation":"La acción (modificar) es funcional, pero habilita la mantenibilidad (no funcional)."},{"id":5,"text":"Los datos de los estudiantes deben transmitirse cifrados con TLS 1.2.","correctZone":"NO_FUNCIONAL","explanation":"Seguridad, restricción técnica."}]}'::jsonb);

-- Pregunta 7 – Construcción de user story (arrastrar palabras)
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 7 – Construye la User Story',
     'Arrastra las palabras correctas para formar la user story del bibliotecario.',
     'DRAG_DROP', 'INTERMEDIATE', 7, 10,
     '{"examMode":true,"dragMode":"FILL_BLANKS","stories":[{"role":"Bibliotecario","action":"ver la lista de préstamos vencidos","benefit":"aplicar las multas correspondientes"}],"tokens":[{"text":"Bibliotecario","type":"ROLE"},{"text":"Estudiante","type":"ROLE"},{"text":"Administrador","type":"ROLE"},{"text":"ver la lista de préstamos vencidos","type":"ACTION"},{"text":"multar automáticamente","type":"ACTION"},{"text":"reservar un libro","type":"ACTION"},{"text":"aplicar las multas correspondientes","type":"BENEFIT"},{"text":"saber qué libros están disponibles","type":"BENEFIT"},{"text":"ahorrar tiempo","type":"BENEFIT"}],"scoring":{"allCorrect":10,"twoCorrect":6,"oneCorrect":3,"noneCorrect":0}}'::jsonb);

-- Pregunta 8 – Reescribe el requisito (TEXT_INPUT)
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 8 – Reescribe el requisito',
     'Corrige el requerimiento ambiguo para hacerlo SMART.',
     'TEXT_INPUT', 'INTERMEDIATE', 8, 10,
     '{"examMode":true,"textInputMode":"REWRITE","items":[{"originalText":"El sistema debe manejar muchas reservas rápido.","highlightWords":["muchas","rápido"],"hints":{"muchas":"Especifica una cantidad concreta (por ejemplo, número de reservas simultáneas).","rápido":"Define un tiempo máximo de respuesta en segundos o milisegundos."},"modelAnswer":"El sistema debe procesar hasta 50 reservas simultáneas en menos de 2 segundos.","evaluation":{"type":"countPatterns","requiredPatterns":["\\d+\\s*(?:segundos?|ms|milisegundos?|minutos?)","\\d+\\s*(?:reservas?|peticiones?|usuarios?)\\s*(?:simultáneas?|concurrentes?)"],"fullScore":10,"partialScore":5,"noScore":0},"scoringFeedback":{"full":"¡Perfecto! Ahora es específico, medible y verificable.","partial":"Has corregido parcialmente. Aún queda un término ambiguo.","none":"No se detectaron mejoras suficientes. Revisa la pista."}}]}'::jsonb);

-- Pregunta 9 – Matching (pares seleccionables): conceptos de validación
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 9 – Matching de conceptos',
     'Empareja cada concepto de validación con su definición correcta.',
     'MATCH_PAIRS', 'INTERMEDIATE', 9, 10,
     '{"examMode":true,"pairs":[{"concept":"Validación","definition":"Confirma que el conjunto de requerimientos satisface las necesidades de los stakeholders."},{"concept":"Verificación","definition":"Confirma que los artefactos de requerimientos cumplen con estándares y reglas establecidos."},{"concept":"Ambigüedad","definition":"Defecto por el cual un requerimiento puede interpretarse de más de una manera."},{"concept":"Incompletitud","definition":"Defecto que ocurre cuando falta información esencial en el requerimiento."}],"pointsPerPair":2.5}'::jsonb);

-- Pregunta 10 – Identificación de lagunas (TEXT_INPUT reflexivo)
INSERT INTO activities (lesson_id, title, description, type, difficulty, order_index, max_score, configuration) VALUES
    (6, 'Pregunta 10 – Identifica lagunas',
     'Escribe al menos tres requisitos que consideres que faltan en la descripción del caso.',
     'TEXT_INPUT', 'INTERMEDIATE', 10, 10,
     '{"examMode":true,"textInputMode":"FREE_TEXT","minLines":3,"caseSummary":"La Universidad Tecnológica del Valle necesita un nuevo sistema de gestión de biblioteca. Actualmente usan un proceso manual con fichas de papel. Los estudiantes pueden pedir prestados hasta 3 libros por 15 días. Los profesores pueden pedir hasta 10 libros por 30 días. El sistema debe registrar préstamos, devoluciones, multas por retraso ($1,000 por día), y permitir reservar libros que estén prestados. La biblioteca tiene 5,000 estudiantes, 500 profesores y 20,000 libros. En horas pico (12 pm - 2 pm), hay hasta 200 solicitudes simultáneas. El personal de biblioteca (5 personas) necesita un panel para gestionar préstamos y generar reportes semanales de libros más prestados. La universidad planea integrar este sistema con el sistema de pagos en línea para cobrar multas automáticamente.","expectedGaps":["¿Cómo se gestionan las altas y bajas de libros en el catálogo?","¿El sistema debe notificar al usuario cuando un libro reservado esté disponible?","¿Qué pasa si un estudiante quiere renovar un préstamo?","¿Existe algún requisito de integración con el sistema de autenticación de la universidad?","¿Se requiere accesibilidad para personas con discapacidad visual?","¿El sistema debe llevar un registro de auditoría de quién realizó cada préstamo o devolución?"],"scoringRubric":"Evalúa tú mismo: si escribiste 3 o más líneas con requisitos faltantes, obtienes 10 puntos."}'::jsonb);